const jobs = $('Get Job').all();

const results = [];

for (const item of jobs) {
  const job = { ...item.json };

  if (job.content) {
    job.content = job.content
      .replace(/\r?\n/g, ' ')
      .replace(/\s{2,}/g, ' ')
      .trim();
  }

  results.push({ json: { job } });
}

return results;

